import jwt
import json
from datetime import datetime, timedelta


class JwtWrapper(object):
    def __init__(self, key, algorithm="HS256"):
        self._key = key
        self._algorithm = algorithm

    @staticmethod
    def _get_current_time():
        return datetime.utcnow()

    @staticmethod
    def _get_expiration_time():
        return datetime.utcnow() + timedelta(days=30)

    def generate_token(self, payload):
        token = jwt.encode(payload, self._key, algorithm=self._algorithm).decode("utf-8")
        return token

    def verify_token(self, token):
        try:
            decoded = jwt.decode(
                token, self._key, algorithms=[self._algorithm], options={"verify_exp": True}
            )
            return json.loads(decoded)

        except Exception as e:
            raise e


